import { fetchGraphQL } from './hasuraClient';
import { GET_EMPLOYEES, GET_EMPLOYEE_BY_ID } from '../graphql/queries/employeeQueries';
import { INSERT_EMPLOYEE, UPDATE_EMPLOYEE, DELETE_EMPLOYEE } from '../graphql/mutations/employeeMutations';

export const EmployeeService = {
  getAll: async () => {
    const data = await fetchGraphQL(GET_EMPLOYEES);
    return data?.employees || [];
  },

  getById: async (id) => {
    const data = await fetchGraphQL(GET_EMPLOYEE_BY_ID, { id });
    return data?.employees_by_pk || null;
  },

  create: async (employeeData) => {
    const data = await fetchGraphQL(INSERT_EMPLOYEE, { object: employeeData });
    return data?.insert_employees_one || null;
  },

  update: async (id, changes) => {
    // changes truyền vào các cột muốn sửa ví dụ: { phone: "099999", status: "active" }
    const data = await fetchGraphQL(UPDATE_EMPLOYEE, { id, changes });
    return data?.update_employees_by_pk || null;
  },

  delete: async (id) => {
    const data = await fetchGraphQL(DELETE_EMPLOYEE, { id });
    return data?.delete_employees_by_pk || null;
  }
};