// graphql/mutations/employeeMutations.js

// 1. THÊM MỚI - Trả về đầy đủ thuộc tính để cập nhật ngay vào State UI
export const INSERT_EMPLOYEE = `
  mutation InsertEmployee($object: employees_insert_input!) {
    insert_employees_one(object: $object) {
      id
      email
      first_name
      last_name
      employee_code
      gender
      address
      document_url
      date_of_birth
      start_date
      phone
      status
      level_id
      role_id
      department_id
      created_at
      updated_at
    }
  }
`;

// 2. CẬP NHẬT - Trả về đầy đủ thuộc tính sau khi sửa thành công
export const UPDATE_EMPLOYEE = `
  mutation UpdateEmployee($id: Int!, $changes: employees_set_input!) {
    update_employees_by_pk(pk_columns: {id: $id}, _set: $changes) {
      id
      email
      first_name
      last_name
      phone
      status
      level_id
      role_id
      department_id
      created_at
      updated_at
      level {
        id
        name
      }
      role {
        id
        name
      }
      department {
        id
        name
      }
    }
  }
`;

// 3. XÓA - Trả về thông tin định danh cơ bản của nhân viên vừa xóa
export const DELETE_EMPLOYEE = `
  mutation DeleteEmployee($id: Int!) {
    delete_employees_by_pk(id: $id) {
      id
      email
      first_name
      last_name
    }
  }
`;